sql:
SELECT best_cvi_score, best_ari_score
FROM best_scores
WHERE experiment_id = 9;

SELECT experiment_id, best_cvi_score
FROM experiments
WHERE best_cvi_score > (SELECT AVG(best_cvi_score) FROM experiments);

SELECT experiment_id
FROM experiments
WHERE cvi_score > 1 AND best_cvi_score > 1;

SELECT e.experiment_id, e.runtime, e.config
FROM experiments e
WHERE e.experiment_id = 0;

external_knowledge:
- Researchers here refer to users with the role 'researcher';
- The 'best CVI score' refers to the highest cluster validity index score achieved in each experiment;
- The query aims to identify researchers whose performance, measured by the average of their best CVI scores, surpasses the average performance of all researchers.

sql:
SELECT user_id, experiment_id, cvi_score
FROM experiments
WHERE cvi_score = (SELECT MAX(cvi_score) FROM experiments);

SELECT experiment_id, cvi_score, ari_score, user_id
FROM iterations
WHERE ari_score > 0.5 AND cvi_score < 0.5;

external_knowledge:
- "Crossed the finish line" metaphorically refers to experiments that have a status of 'completed';
- "Trail they followed" refers to the dataset file path;
- "Expeditions that sought treasure in the lands marked by IDs 0 and 1" means experiments associated with datasets having `dataset_id` 0 or 1.

sql:
SELECT dataset_name, description
FROM datasets
WHERE dataset_id IN (
    SELECT similar_dataset_id 
    FROM similar_datasets
);

SELECT experiments.cvi_score, datasets.dataset_name
FROM experiments
JOIN datasets ON experiments.dataset_id = datasets.dataset_id;

SELECT experiment_id,
       AVG(cvi_score) OVER (PARTITION BY experiment_id ORDER BY iteration ROWS BETWEEN 2 PRECEDING AND CURRENT ROW) AS moving_avg_cvi_score
FROM experiments;

SELECT outcome
FROM experiment_logs
WHERE outcome = 'success' OR outcome = 'failure';
